package com.enterprise.saml.security;

import org.springframework.stereotype.Component;

import jakarta.annotation.PostConstruct;
import java.time.Instant;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

/**
 * Thread-safe cache to track consumed SAML assertion IDs and prevent replay attacks.
 * Assertion IDs are stored with their expiration time and periodically cleaned up.
 */
@Component
public class AssertionReplayCache {

    private final ConcurrentHashMap<String, Instant> consumedAssertionIds = new ConcurrentHashMap<>();
    private final ScheduledExecutorService cleanupExecutor = Executors.newSingleThreadScheduledExecutor();

    // Maximum age for cache entries (should be >= maximum allowed assertion lifetime)
    private static final long MAX_CACHE_ENTRY_AGE_MINUTES = 60;

    @PostConstruct
    public void init() {
        // Periodically clean up expired entries every 5 minutes
        cleanupExecutor.scheduleAtFixedRate(this::cleanupExpiredEntries, 5, 5, TimeUnit.MINUTES);
    }

    /**
     * Attempts to consume an assertion ID. Returns true if the ID was successfully
     * consumed (i.e., it was not previously seen). Returns false if the ID was
     * already consumed (replay detected).
     *
     * @param assertionId The unique assertion ID from the SAML response
     * @param expirationTime The time at which the assertion expires (from Conditions/NotOnOrAfter)
     * @return true if the assertion ID is fresh, false if it's a replay
     */
    public boolean consumeAssertionId(String assertionId, Instant expirationTime) {
        if (assertionId == null || assertionId.isBlank()) {
            return false;
        }

        // Use the assertion's expiration time, but cap it at our maximum cache age
        Instant maxExpiration = Instant.now().plusSeconds(MAX_CACHE_ENTRY_AGE_MINUTES * 60);
        Instant effectiveExpiration = expirationTime != null && expirationTime.isBefore(maxExpiration)
                ? expirationTime : maxExpiration;

        // putIfAbsent returns null if the key was not present (success), or the existing value (replay)
        Instant existing = consumedAssertionIds.putIfAbsent(assertionId, effectiveExpiration);
        return existing == null;
    }

    /**
     * Check if an assertion ID has already been consumed.
     */
    public boolean isReplay(String assertionId) {
        if (assertionId == null || assertionId.isBlank()) {
            return true; // Treat missing assertion ID as potential replay
        }
        return consumedAssertionIds.containsKey(assertionId);
    }

    private void cleanupExpiredEntries() {
        Instant now = Instant.now();
        consumedAssertionIds.entrySet().removeIf(entry -> entry.getValue().isBefore(now));
    }

    public void destroy() {
        cleanupExecutor.shutdown();
    }
}

