package com.enterprise.saml.security;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Component;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;

import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.KeyInfo;
import javax.xml.crypto.dsig.keyinfo.X509Data;
import java.io.FileInputStream;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.time.Instant;
import java.time.format.DateTimeParseException;
import java.util.*;

@Component
public class SamlResponseValidator {

    private static final String SAML_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String SAML_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";

    // Clock skew tolerance in seconds
    private static final int CLOCK_SKEW_SECONDS = 120;

    @Value("${saml.idp.certificate.path}")
    private String idpCertificatePath;

    @Value("${saml.sp.entity-id}")
    private String spEntityId;

    private final AssertionReplayCache replayCache;

    public SamlResponseValidator(AssertionReplayCache replayCache) {
        this.replayCache = replayCache;
    }

    /**
     * Comprehensive validation of a SAML Response document.
     */
    public SamlValidationResult validate(Document samlDocument) {
        try {
            Element responseElement = samlDocument.getDocumentElement();

            // 1. Validate response status
            if (!validateResponseStatus(responseElement)) {
                return SamlValidationResult.failure("SAML Response status is not Success");
            }

            // 2. Validate XML Signature
            if (!validateSignature(samlDocument)) {
                return SamlValidationResult.failure("SAML Response signature validation failed");
            }

            // 3. Extract assertion
            NodeList assertions = responseElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "Assertion");
            if (assertions.getLength() == 0) {
                return SamlValidationResult.failure("No assertion found in SAML Response");
            }
            Element assertionElement = (Element) assertions.item(0);

            // 4. Validate assertion ID exists and check for replay
            String assertionId = assertionElement.getAttribute("ID");
            if (assertionId == null || assertionId.isBlank()) {
                return SamlValidationResult.failure("Assertion ID is missing");
            }

            // 5. Validate time conditions (NotBefore, NotOnOrAfter)
            Instant notOnOrAfter = validateConditions(assertionElement);
            if (notOnOrAfter == null) {
                return SamlValidationResult.failure("Assertion conditions validation failed (expired or not yet valid)");
            }

            // 6. Check replay - this MUST happen after signature validation and time validation
            if (!replayCache.consumeAssertionId(assertionId, notOnOrAfter)) {
                return SamlValidationResult.failure("Replay attack detected: Assertion ID '" + assertionId + "' has already been consumed");
            }

            // 7. Validate audience restriction
            if (!validateAudienceRestriction(assertionElement)) {
                return SamlValidationResult.failure("Audience restriction validation failed");
            }

            // 8. Validate SubjectConfirmation
            if (!validateSubjectConfirmation(assertionElement)) {
                return SamlValidationResult.failure("Subject confirmation validation failed");
            }

            // 9. Extract user attributes
            Map<String, String> attributes = extractAttributes(assertionElement);
            String nameId = extractNameId(assertionElement);

            if (nameId == null || nameId.isBlank()) {
                return SamlValidationResult.failure("NameID is missing from assertion");
            }

            return SamlValidationResult.success(nameId, attributes, assertionId);

        } catch (Exception e) {
            return SamlValidationResult.failure("SAML validation error: " + e.getMessage());
        }
    }

    private boolean validateResponseStatus(Element responseElement) {
        NodeList statusCodes = responseElement.getElementsByTagNameNS(SAML_PROTOCOL_NS, "StatusCode");
        if (statusCodes.getLength() == 0) {
            return false;
        }
        Element statusCode = (Element) statusCodes.item(0);
        String value = statusCode.getAttribute("Value");
        return "urn:oasis:names:tc:SAML:2.0:status:Success".equals(value);
    }

    private boolean validateSignature(Document document) {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(XMLSignature.XMLNS, "Signature");
            if (signatureNodes.getLength() == 0) {
                return false;
            }

            PublicKey idpPublicKey = loadIdpPublicKey();

            for (int i = 0; i < signatureNodes.getLength(); i++) {
                Element signatureElement = (Element) signatureNodes.item(i);
                DOMValidateContext validateContext = new DOMValidateContext(idpPublicKey, signatureElement);
                validateContext.setProperty("org.jcp.xml.dsig.secureValidation", Boolean.TRUE);

                XMLSignatureFactory factory = XMLSignatureFactory.getInstance("DOM");
                XMLSignature signature = factory.unmarshalXMLSignature(validateContext);

                if (!signature.validate(validateContext)) {
                    return false;
                }

                // Verify that the signature covers the expected elements
                if (!verifySignatureReferences(signature, document)) {
                    return false;
                }
            }
            return true;
        } catch (Exception e) {
            return false;
        }
    }

    private boolean verifySignatureReferences(XMLSignature signature, Document document) {
        try {
            List<Reference> references = signature.getSignedInfo().getReferences();
            for (Reference ref : references) {
                String uri = ref.getURI();
                if (uri != null && uri.startsWith("#")) {
                    String id = uri.substring(1);
                    // Verify the referenced element exists in the document
                    Element referencedElement = document.getElementById(id);
                    if (referencedElement == null) {
                        // Try finding by attribute
                        NodeList allElements = document.getElementsByTagName("*");
                        boolean found = false;
                        for (int i = 0; i < allElements.getLength(); i++) {
                            Element el = (Element) allElements.item(i);
                            if (id.equals(el.getAttribute("ID"))) {
                                found = true;
                                break;
                            }
                        }
                        if (!found) return false;
                    }
                }
            }
            return true;
        } catch (Exception e) {
            return false;
        }
    }

    /**
     * Validates time-based conditions. Returns the NotOnOrAfter instant if valid, null otherwise.
     */
    private Instant validateConditions(Element assertionElement) {
        NodeList conditionsList = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "Conditions");
        if (conditionsList.getLength() == 0) {
            return null; // Conditions element is required
        }

        Element conditions = (Element) conditionsList.item(0);
        Instant now = Instant.now();

        String notBeforeStr = conditions.getAttribute("NotBefore");
        String notOnOrAfterStr = conditions.getAttribute("NotOnOrAfter");

        Instant notOnOrAfter = null;

        try {
            if (notBeforeStr != null && !notBeforeStr.isBlank()) {
                Instant notBefore = Instant.parse(notBeforeStr);
                // Allow clock skew
                if (now.plusSeconds(CLOCK_SKEW_SECONDS).isBefore(notBefore)) {
                    return null; // Assertion is not yet valid
                }
            }

            if (notOnOrAfterStr != null && !notOnOrAfterStr.isBlank()) {
                notOnOrAfter = Instant.parse(notOnOrAfterStr);
                // Allow clock skew
                if (now.minusSeconds(CLOCK_SKEW_SECONDS).isAfter(notOnOrAfter)) {
                    return null; // Assertion has expired
                }
            } else {
                return null; // NotOnOrAfter is required for security
            }
        } catch (DateTimeParseException e) {
            return null;
        }

        return notOnOrAfter;
    }

    private boolean validateAudienceRestriction(Element assertionElement) {
        NodeList audienceRestrictions = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "AudienceRestriction");
        if (audienceRestrictions.getLength() == 0) {
            return false; // Audience restriction should be present
        }

        Element audienceRestriction = (Element) audienceRestrictions.item(0);
        NodeList audiences = audienceRestriction.getElementsByTagNameNS(SAML_ASSERTION_NS, "Audience");

        for (int i = 0; i < audiences.getLength(); i++) {
            String audienceValue = audiences.item(i).getTextContent().trim();
            if (spEntityId.equals(audienceValue)) {
                return true;
            }
        }
        return false;
    }

    private boolean validateSubjectConfirmation(Element assertionElement) {
        NodeList subjectConfirmations = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "SubjectConfirmation");
        if (subjectConfirmations.getLength() == 0) {
            return false;
        }

        Instant now = Instant.now();

        for (int i = 0; i < subjectConfirmations.getLength(); i++) {
            Element subjectConfirmation = (Element) subjectConfirmations.item(i);
            String method = subjectConfirmation.getAttribute("Method");

            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                NodeList confirmationData = subjectConfirmation.getElementsByTagNameNS(SAML_ASSERTION_NS, "SubjectConfirmationData");
                if (confirmationData.getLength() > 0) {
                    Element data = (Element) confirmationData.item(0);

                    // Validate NotOnOrAfter in SubjectConfirmationData
                    String notOnOrAfterStr = data.getAttribute("NotOnOrAfter");
                    if (notOnOrAfterStr != null && !notOnOrAfterStr.isBlank()) {
                        try {
                            Instant notOnOrAfter = Instant.parse(notOnOrAfterStr);
                            if (now.minusSeconds(CLOCK_SKEW_SECONDS).isAfter(notOnOrAfter)) {
                                continue; // This confirmation has expired
                            }
                        } catch (DateTimeParseException e) {
                            continue;
                        }
                    }

                    // Validate Recipient matches our ACS URL
                    String recipient = data.getAttribute("Recipient");
                    if (recipient != null && !recipient.isBlank()) {
                        // Recipient validation would check against our ACS URL
                        // For now, we accept it if present
                    }

                    return true;
                }
            }
        }
        return false;
    }

    private String extractNameId(Element assertionElement) {
        NodeList nameIds = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "NameID");
        if (nameIds.getLength() > 0) {
            return nameIds.item(0).getTextContent().trim();
        }
        return null;
    }

    private Map<String, String> extractAttributes(Element assertionElement) {
        Map<String, String> attributes = new LinkedHashMap<>();

        NodeList attributeStatements = assertionElement.getElementsByTagNameNS(SAML_ASSERTION_NS, "AttributeStatement");
        if (attributeStatements.getLength() == 0) {
            return attributes;
        }

        Element attributeStatement = (Element) attributeStatements.item(0);
        NodeList attributeNodes = attributeStatement.getElementsByTagNameNS(SAML_ASSERTION_NS, "Attribute");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attribute = (Element) attributeNodes.item(i);
            String name = attribute.getAttribute("Name");

            NodeList values = attribute.getElementsByTagNameNS(SAML_ASSERTION_NS, "AttributeValue");
            if (values.getLength() > 0) {
                String value = values.item(0).getTextContent().trim();
                // Sanitize attribute name and value
                if (isValidAttributeName(name)) {
                    attributes.put(name, sanitizeAttributeValue(value));
                }
            }
        }

        return attributes;
    }

    private boolean isValidAttributeName(String name) {
        return name != null && !name.isBlank() && name.length() <= 256;
    }

    private String sanitizeAttributeValue(String value) {
        if (value == null) return "";
        // Remove any control characters except common whitespace
        return value.replaceAll("[\\x00-\\x08\\x0B\\x0C\\x0E-\\x1F\\x7F]", "").trim();
    }

    private PublicKey loadIdpPublicKey() throws Exception {
        CertificateFactory cf = CertificateFactory.getInstance("X.509");
        try (FileInputStream fis = new FileInputStream(idpCertificatePath)) {
            X509Certificate cert = (X509Certificate) cf.generateCertificate(fis);
            // Verify the certificate is still valid
            cert.checkValidity();
            return cert.getPublicKey();
        }
    }
}

