package com.enterprise.saml.security;

import java.util.Collections;
import java.util.Map;

public class SamlValidationResult {

    private final boolean valid;
    private final String errorMessage;
    private final String nameId;
    private final Map<String, String> attributes;
    private final String assertionId;

    private SamlValidationResult(boolean valid, String errorMessage, String nameId,
                                  Map<String, String> attributes, String assertionId) {
        this.valid = valid;
        this.errorMessage = errorMessage;
        this.nameId = nameId;
        this.attributes = attributes != null ? Collections.unmodifiableMap(attributes) : Collections.emptyMap();
        this.assertionId = assertionId;
    }

    public static SamlValidationResult success(String nameId, Map<String, String> attributes, String assertionId) {
        return new SamlValidationResult(true, null, nameId, attributes, assertionId);
    }

    public static SamlValidationResult failure(String errorMessage) {
        return new SamlValidationResult(false, errorMessage, null, null, null);
    }

    public boolean isValid() { return valid; }
    public String getErrorMessage() { return errorMessage; }
    public String getNameId() { return nameId; }
    public Map<String, String> getAttributes() { return attributes; }
    public String getAssertionId() { return assertionId; }
}

