package com.enterprise.saml.config;

import com.enterprise.saml.security.SamlResponseValidator;
import com.enterprise.saml.security.SamlValidationResult;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;
import org.w3c.dom.Document;
import org.xml.sax.InputSource;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.IOException;
import java.io.StringReader;
import java.util.Base64;
import java.util.Collections;
import java.util.List;
import java.util.Map;

@Component
public class SamlAuthenticationFilter extends OncePerRequestFilter {

    private static final Logger log = LoggerFactory.getLogger(SamlAuthenticationFilter.class);

    private final SamlResponseValidator samlResponseValidator;

    // Maximum allowed SAML response size (256 KB)
    private static final int MAX_SAML_RESPONSE_SIZE = 256 * 1024;

    public SamlAuthenticationFilter(SamlResponseValidator samlResponseValidator) {
        this.samlResponseValidator = samlResponseValidator;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {

        if ("/saml/acs".equals(request.getRequestURI()) && "POST".equalsIgnoreCase(request.getMethod())) {
            processSamlResponse(request, response);
            return;
        }

        // Check if user is already authenticated via session
        HttpSession session = request.getSession(false);
        if (session != null) {
            String nameId = (String) session.getAttribute("saml.nameId");
            if (nameId != null) {
                List<SimpleGrantedAuthority> authorities = Collections.singletonList(
                        new SimpleGrantedAuthority("ROLE_USER"));
                UsernamePasswordAuthenticationToken auth =
                        new UsernamePasswordAuthenticationToken(nameId, null, authorities);
                SecurityContextHolder.getContext().setAuthentication(auth);
            }
        }

        filterChain.doFilter(request, response);
    }

    private void processSamlResponse(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String samlResponseParam = request.getParameter("SAMLResponse");

        if (samlResponseParam == null || samlResponseParam.isBlank()) {
            log.warn("Missing SAMLResponse parameter from {}", request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing SAMLResponse");
            return;
        }

        // Check size before decoding
        if (samlResponseParam.length() > MAX_SAML_RESPONSE_SIZE) {
            log.warn("SAMLResponse exceeds maximum allowed size from {}", request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "SAMLResponse too large");
            return;
        }

        try {
            byte[] decodedBytes = Base64.getDecoder().decode(samlResponseParam);
            String samlXml = new String(decodedBytes, java.nio.charset.StandardCharsets.UTF_8);

            Document samlDocument = parseSecureXml(samlXml);
            if (samlDocument == null) {
                log.warn("Failed to parse SAML Response XML from {}", request.getRemoteAddr());
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid SAML Response");
                return;
            }

            SamlValidationResult result = samlResponseValidator.validate(samlDocument);

            if (!result.isValid()) {
                log.warn("SAML validation failed: {} (from {})", result.getErrorMessage(), request.getRemoteAddr());
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "SAML authentication failed");
                return;
            }

            // Create authenticated session
            // Invalidate existing session to prevent session fixation
            HttpSession oldSession = request.getSession(false);
            if (oldSession != null) {
                oldSession.invalidate();
            }

            HttpSession session = request.getSession(true);
            session.setAttribute("saml.nameId", result.getNameId());
            session.setAttribute("saml.assertionId", result.getAssertionId());
            session.setAttribute("saml.authTime", System.currentTimeMillis());

            // Store user attributes in session
            Map<String, String> attributes = result.getAttributes();
            for (Map.Entry<String, String> entry : attributes.entrySet()) {
                session.setAttribute("saml.attr." + entry.getKey(), entry.getValue());
            }

            // Set session timeout (30 minutes)
            session.setMaxInactiveInterval(1800);

            // Set authentication in security context
            List<SimpleGrantedAuthority> authorities = Collections.singletonList(
                    new SimpleGrantedAuthority("ROLE_USER"));
            UsernamePasswordAuthenticationToken auth =
                    new UsernamePasswordAuthenticationToken(result.getNameId(), null, authorities);
            SecurityContextHolder.getContext().setAuthentication(auth);

            log.info("SAML authentication successful for user: {} (assertionId: {})",
                    result.getNameId(), result.getAssertionId());

            response.sendRedirect("/dashboard");

        } catch (IllegalArgumentException e) {
            log.warn("Invalid Base64 in SAMLResponse from {}", request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid SAMLResponse encoding");
        } catch (Exception e) {
            log.error("Error processing SAML Response from {}: {}", request.getRemoteAddr(), e.getMessage());
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Authentication error");
        }
    }

    /**
     * Parse XML securely, preventing XXE and other XML-based attacks.
     */
    private Document parseSecureXml(String xml) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();

            // Set an error handler that rejects malformed XML
            builder.setErrorHandler(new org.xml.sax.helpers.DefaultHandler() {
                @Override
                public void error(org.xml.sax.SAXParseException e) throws org.xml.sax.SAXException {
                    throw e;
                }

                @Override
                public void fatalError(org.xml.sax.SAXParseException e) throws org.xml.sax.SAXException {
                    throw e;
                }
            });

            return builder.parse(new InputSource(new StringReader(xml)));
        } catch (Exception e) {
            log.error("XML parsing error: {}", e.getMessage());
            return null;
        }
    }
}

// ==================== SAML Login Controller ====================

package com.enterprise.saml.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.net.URLEncoder;
import java.nio.charset.StandardCharsets;
import java.util.UUID;

@Controller
public class SamlController {

    @Value("${saml.idp.sso-url}")
    private String idpSsoUrl;

    @Value("${saml.sp.entity-id}")
    private String spEntityId;

    @Value("${saml.sp.acs-url}")
    private String acsUrl;

    @GetMapping("/saml/login")
    public String initiateLogin(HttpServletRequest request) {
        // Generate AuthnRequest ID for correlation
        String requestId = "_" + UUID.randomUUID().toString();

        // Store request ID in session for response validation
        HttpSession session = request.getSession(true);
        session.setAttribute("saml.authnRequestId", requestId);

        String samlRequest = buildAuthnRequest(requestId);
        String encodedRequest = java.util.Base64.getEncoder().encodeToString(
                samlRequest.getBytes(StandardCharsets.UTF_8));

        String redirectUrl = idpSsoUrl + "?SAMLRequest=" +
                URLEncoder.encode(encodedRequest, StandardCharsets.UTF_8);

        return "redirect:" + redirectUrl;
    }

    @GetMapping("/dashboard")
    public String dashboard(HttpServletRequest request, Model model) {
        HttpSession session = request.getSession(false);
        if (session == null) {
            return "redirect:/saml/login";
        }

        String nameId = (String) session.getAttribute("saml.nameId");
        if (nameId == null) {
            return "redirect:/saml/login";
        }

        model.addAttribute("username", nameId);
        model.addAttribute("email", session.getAttribute("saml.attr.email"));
        model.addAttribute("firstName", session.getAttribute("saml.attr.firstName"));
        model.addAttribute("lastName", session.getAttribute("saml.attr.lastName"));
        model.addAttribute("department", session.getAttribute("saml.attr.department"));

        return "dashboard";
    }

    @GetMapping("/logout")
    public String logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }
        return "redirect:/saml/login";
    }

    private String buildAuthnRequest(String requestId) {
        String issueInstant = java.time.Instant.now().toString();
        return "<?xml version=\"1.0\" encoding=\"UTF-8\"?>" +
                "<samlp:AuthnRequest xmlns:samlp=\"urn:oasis:names:tc:SAML:2.0:protocol\" " +
                "xmlns:saml=\"urn:oasis:names:tc:SAML:2.0:assertion\" " +
                "ID=\"" + requestId + "\" " +
                "Version=\"2.0\" " +
                "IssueInstant=\"" + issueInstant + "\" " +
                "AssertionConsumerServiceURL=\"" + acsUrl + "\" " +
                "ProtocolBinding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\">" +
                "<saml:Issuer>" + spEntityId + "</saml:Issuer>" +
                "<samlp:NameIDPolicy Format=\"urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress\" " +
                "AllowCreate=\"false\"/>" +
                "</samlp:AuthnRequest>";
    }
}

